async (params, browser) => {
  // Open page
  await browser.open('https://www.coinbase.com/explore')

  // Wait for content
  await browser.waitForSelector('table, a[href*=\'/price/\']', 15000)

  // Let page render
  await browser.wait(2500)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(2000)

  // Extract data
  const page_data = await browser.evaluate(`const assets = []; document.querySelectorAll('table tbody tr, a[href*="/price/"]').forEach((el, i) => { if (i >= 30) return; const name = el.querySelector('td:first-child, h2, p')?.textContent?.trim() || el.textContent?.trim() || ''; const price = el.querySelector('td:nth-child(2), [class*="Price"]')?.textContent?.trim() || ''; const change = el.querySelector('td:nth-child(3), [class*="Change"]')?.textContent?.trim() || ''; const link = el.querySelector('a[href*="/price/"]') || (el.matches?.('a[href*="/price/"]') ? el : null); const url = link ? link.href : ''; if (name && name.length < 100) assets.push({ name, price, change_24h: change, url }); }); return { assets, url: window.location.href }`)

  return page_data
}
